import hashlib

def hash_file(filename):
    """Creates a hash of a file for integrity checking."""
    with open(filename, "rb") as f:
        file_hash = hashlib.sha256()
        while True:
            data = f.read(65536)
            if not data:
                break
            file_hash.update(data)
    return file_hash.hexdigest()